public int[] advantageCount(int[] nums1, int[] nums2) {
    Arrays.sort(nums1);
    int n = nums1.length;
    int[][] arr = new int[n][2];
    for(int i=0;i<n;i++){
        arr[i][0]=nums2[i];
        arr[i][1]=i;
    }
    Arrays.sort(arr,(a,b)->Integer.compare(a[0],b[0]));
    int[] ans=new int[n];
    int left=0,right=n-1;
    for(int i=n-1;i>=0;i--){
        if(nums1[right]>arr[i][0]){
            ans[arr[i][1]]=nums1[right--];
        }else{
            ans[arr[i][1]]=nums1[left++];
        }
    }
    return ans;
}

code.python:
def advantageCount(nums1, nums2):
    nums1.sort()
    pairs = sorted([(v,i) for i,v in enumerate(nums2)])
    ans=[0]*len(nums1)
    left,right=0,len(nums1)-1
    for value,index in reversed(pairs):
        if nums1[right] > value:
            ans[index]=nums1[right]
            right-=1
        else:
            ans[index]=nums1[left]
            left+=1
    return ans

